import { useState, useEffect, useCallback } from 'react';
import {
    Table, Button, Input, Modal, Form, Space, Popconfirm, Tag, Tooltip, Empty, Select
} from 'antd';
import {
    PlusOutlined, EditOutlined, DeleteOutlined,
    SearchOutlined, DownloadOutlined, ReloadOutlined, UploadOutlined,
    FileExcelOutlined, FilterOutlined
} from '@ant-design/icons';
import { useSupabaseCrud } from '../../hooks/useSupabase';
import CsvImportModal from './CsvImportModal';
import { useAuth } from '../../contexts/AuthContext';

export default function CrudTable({ tableName, title, columns, formFields, searchField, filterConfig = [] }) {
    const { data, loading, total, fetchData, createRecord, updateRecord, deleteRecord, fetchAll } = useSupabaseCrud(tableName);
    const { canEdit, canDelete } = useAuth();
    const [modalOpen, setModalOpen] = useState(false);
    const [editingRecord, setEditingRecord] = useState(null);
    const [search, setSearch] = useState('');
    const [pagination, setPagination] = useState({ current: 1, pageSize: 10 });
    const [importModalOpen, setImportModalOpen] = useState(false);
    const [filters, setFilters] = useState({});
    const [showFilters, setShowFilters] = useState(false);
    const [form] = Form.useForm();

    const userCanEdit = canEdit();
    const userCanDelete = canDelete();

    const loadData = useCallback(() => {
        fetchData({ page: pagination.current, pageSize: pagination.pageSize, search, searchField, filters });
    }, [fetchData, pagination.current, pagination.pageSize, search, searchField, filters]);

    useEffect(() => { loadData(); }, [loadData]);

    const handleAdd = () => {
        setEditingRecord(null);
        form.resetFields();
        setModalOpen(true);
    };

    const handleEdit = (record) => {
        setEditingRecord(record);
        form.setFieldsValue(record);
        setModalOpen(true);
    };

    const handleDelete = async (id) => {
        const ok = await deleteRecord(id);
        if (ok) loadData();
    };

    const handleSubmit = async () => {
        try {
            const values = await form.validateFields();
            let ok;
            if (editingRecord) {
                ok = await updateRecord(editingRecord.id, values);
            } else {
                ok = await createRecord(values);
            }
            if (ok) {
                setModalOpen(false);
                form.resetFields();
                loadData();
            }
        } catch (err) {
            /* validation error, ant handles display */
        }
    };

    const handleTableChange = (pag) => {
        setPagination({ current: pag.current, pageSize: pag.pageSize });
    };

    const handleSearch = (value) => {
        setSearch(value);
        setPagination({ ...pagination, current: 1 });
    };

    const handleFilterChange = (key, value) => {
        const newFilters = { ...filters, [key]: value };
        setFilters(newFilters);
        setPagination({ ...pagination, current: 1 });
    };

    const handleClearFilters = () => {
        setFilters({});
        setPagination({ ...pagination, current: 1 });
    };

    const activeFilterCount = Object.values(filters).filter(v => v !== undefined && v !== null && v !== '').length;

    const handleExportCSV = () => {
        if (!data.length) return;
        const headers = columns.filter(c => c.dataIndex).map(c => c.title);
        const keys = columns.filter(c => c.dataIndex).map(c => c.dataIndex);
        const csvContent = [
            headers.join(','),
            ...data.map(row => keys.map(k => `"${row[k] ?? ''}"`).join(','))
        ].join('\n');
        const blob = new Blob(['\uFEFF' + csvContent], { type: 'text/csv;charset=utf-8;' });
        const url = URL.createObjectURL(blob);
        const link = document.createElement('a');
        link.href = url;
        link.download = `${tableName}_${new Date().toISOString().slice(0, 10)}.csv`;
        link.click();
        URL.revokeObjectURL(url);
    };

    const handleExportExcel = async () => {
        try {
            const allData = await fetchAll();
            if (!allData.length) return;

            const { utils, writeFile } = await import('xlsx');
            const headers = columns.filter(c => c.dataIndex).map(c => c.title);
            const keys = columns.filter(c => c.dataIndex).map(c => c.dataIndex);
            const rows = allData.map(row => {
                const obj = {};
                keys.forEach((k, i) => { obj[headers[i]] = row[k] ?? ''; });
                return obj;
            });

            const ws = utils.json_to_sheet(rows);
            ws['!cols'] = headers.map(h => ({ wch: Math.max(h.length * 2, 15) }));
            const wb = utils.book_new();
            utils.book_append_sheet(wb, ws, title.slice(0, 31));
            writeFile(wb, `${tableName}_${new Date().toISOString().slice(0, 10)}.xlsx`);
        } catch (err) {
            console.error('Excel export error:', err);
        }
    };

    // Action column — ซ่อนตาม role
    const actionColumn = userCanEdit ? {
        title: 'จัดการ',
        key: 'actions',
        width: userCanDelete ? 120 : 80,
        align: 'center',
        render: (_, record) => (
            <Space size={4}>
                <Tooltip title="แก้ไข">
                    <Button className="action-btn edit" icon={<EditOutlined />} onClick={() => handleEdit(record)} />
                </Tooltip>
                {userCanDelete && (
                    <Popconfirm
                        title="ยืนยันการลบ"
                        description="คุณต้องการลบข้อมูลนี้ใช่หรือไม่?"
                        onConfirm={() => handleDelete(record.id)}
                        okText="ลบ"
                        cancelText="ยกเลิก"
                        okButtonProps={{ danger: true }}
                    >
                        <Tooltip title="ลบ">
                            <Button className="action-btn delete" icon={<DeleteOutlined />} />
                        </Tooltip>
                    </Popconfirm>
                )}
            </Space>
        ),
    } : null;

    const allColumns = actionColumn ? [...columns, actionColumn] : [...columns];

    return (
        <div className="crud-container">
            <div className="crud-header">
                <div className="crud-header-left">
                    <span className="crud-title">{title}</span>
                    <Tag className="crud-count">{total} รายการ</Tag>
                </div>
                <div className="crud-header-right">
                    {searchField && (
                        <Input.Search
                            placeholder="ค้นหา..."
                            allowClear
                            onSearch={handleSearch}
                            style={{ width: 220 }}
                            prefix={<SearchOutlined />}
                        />
                    )}
                    {filterConfig.length > 0 && (
                        <Tooltip title="กรองข้อมูล">
                            <Button
                                icon={<FilterOutlined />}
                                onClick={() => setShowFilters(!showFilters)}
                                className={`export-btn ${activeFilterCount > 0 ? 'filter-active' : ''}`}
                            >
                                กรอง {activeFilterCount > 0 && `(${activeFilterCount})`}
                            </Button>
                        </Tooltip>
                    )}
                    <Tooltip title="รีเฟรช">
                        <Button icon={<ReloadOutlined />} onClick={loadData} className="export-btn" />
                    </Tooltip>
                    {userCanEdit && (
                        <Button icon={<UploadOutlined />} onClick={() => setImportModalOpen(true)} className="export-btn">
                            Import CSV
                        </Button>
                    )}
                    <Button icon={<DownloadOutlined />} onClick={handleExportCSV} className="export-btn">
                        Export CSV
                    </Button>
                    <Button icon={<FileExcelOutlined />} onClick={handleExportExcel} className="export-btn export-excel-btn">
                        Export Excel
                    </Button>
                    {userCanEdit && (
                        <Button type="primary" icon={<PlusOutlined />} onClick={handleAdd} className="add-btn">
                            เพิ่มข้อมูล
                        </Button>
                    )}
                </div>
            </div>

            {/* Advanced Filter Bar */}
            {filterConfig.length > 0 && showFilters && (
                <div className="filter-bar">
                    <div className="filter-bar-inner">
                        {filterConfig.map(f => (
                            <div key={f.key} className="filter-item">
                                <label className="filter-label">{f.label}</label>
                                <Select
                                    placeholder={`เลือก${f.label}`}
                                    allowClear
                                    value={filters[f.key] || undefined}
                                    onChange={val => handleFilterChange(f.key, val)}
                                    style={{ width: 160 }}
                                    size="small"
                                    options={f.options.map(o => typeof o === 'object' ? o : { label: String(o), value: o })}
                                />
                            </div>
                        ))}
                        {activeFilterCount > 0 && (
                            <Button size="small" onClick={handleClearFilters} style={{ alignSelf: 'flex-end' }}>
                                ล้างตัวกรอง
                            </Button>
                        )}
                    </div>
                </div>
            )}

            <Table
                dataSource={data}
                columns={allColumns}
                rowKey="id"
                loading={loading}
                pagination={{
                    current: pagination.current,
                    pageSize: pagination.pageSize,
                    total,
                    showSizeChanger: true,
                    showTotal: (t) => `ทั้งหมด ${t} รายการ`,
                    pageSizeOptions: ['10', '20', '50'],
                }}
                onChange={handleTableChange}
                locale={{ emptyText: <Empty description="ยังไม่มีข้อมูล" /> }}
                scroll={{ x: 'max-content' }}
            />

            <Modal
                title={editingRecord ? `แก้ไข${title}` : `เพิ่ม${title}`}
                open={modalOpen}
                onCancel={() => { setModalOpen(false); form.resetFields(); }}
                onOk={handleSubmit}
                okText={editingRecord ? 'บันทึก' : 'เพิ่ม'}
                cancelText="ยกเลิก"
                width={640}
                className="crud-modal"
                destroyOnClose
            >
                <Form form={form} layout="vertical" style={{ marginTop: 16 }}>
                    {formFields}
                </Form>
            </Modal>

            <CsvImportModal
                open={importModalOpen}
                onClose={() => setImportModalOpen(false)}
                tableName={tableName}
                columns={columns}
                onSuccess={loadData}
            />
        </div>
    );
}

import { useState, useRef } from 'react';
import { Modal, Button, Table, Select, Progress, Alert, Steps, Tag, Space, Upload } from 'antd';
import {
    UploadOutlined, FileTextOutlined, CheckCircleOutlined,
    WarningOutlined, CloudUploadOutlined, ArrowRightOutlined
} from '@ant-design/icons';

const { Dragger } = Upload;

/**
 * Parse CSV text → array of objects
 * รองรับ UTF-8 + BOM, comma/semicolon, ค่าที่มี quotes
 */
function parseCsv(text) {
    // Remove BOM
    const clean = text.replace(/^\uFEFF/, '');
    const lines = clean.split(/\r?\n/).filter(line => line.trim());
    if (lines.length < 2) return { headers: [], rows: [] };

    // Detect delimiter
    const delimiter = lines[0].includes(';') && !lines[0].includes(',') ? ';' : ',';

    const parseLine = (line) => {
        const result = [];
        let current = '';
        let inQuotes = false;

        for (let i = 0; i < line.length; i++) {
            const char = line[i];
            if (char === '"') {
                if (inQuotes && line[i + 1] === '"') {
                    current += '"';
                    i++;
                } else {
                    inQuotes = !inQuotes;
                }
            } else if (char === delimiter && !inQuotes) {
                result.push(current.trim());
                current = '';
            } else {
                current += char;
            }
        }
        result.push(current.trim());
        return result;
    };

    const headers = parseLine(lines[0]);
    const rows = [];
    for (let i = 1; i < lines.length; i++) {
        const vals = parseLine(lines[i]);
        // ข้ามแถวว่าง
        if (vals.every(v => !v)) continue;
        const obj = {};
        headers.forEach((h, idx) => {
            obj[h] = vals[idx] || '';
        });
        obj._rowNum = i + 1; // เก็บเลขแถวไว้ reference
        rows.push(obj);
    }
    return { headers, rows };
}

export default function CsvImportModal({ open, onClose, tableName, columns, onSuccess }) {
    const [step, setStep] = useState(0); // 0=upload, 1=preview+map, 2=importing, 3=result
    const [csvHeaders, setCsvHeaders] = useState([]);
    const [csvRows, setCsvRows] = useState([]);
    const [mapping, setMapping] = useState({}); // csvHeader → dbColumn
    const [progress, setProgress] = useState(0);
    const [importing, setImporting] = useState(false);
    const [result, setResult] = useState({ success: 0, failed: 0, errors: [] });
    const fileInputRef = useRef(null);

    // DB columns จาก columns prop (ตัดคอลัมน์ actions ออก)
    const dbColumns = columns
        .filter(c => c.dataIndex)
        .map(c => ({ label: c.title, value: c.dataIndex }));

    const reset = () => {
        setStep(0);
        setCsvHeaders([]);
        setCsvRows([]);
        setMapping({});
        setProgress(0);
        setImporting(false);
        setResult({ success: 0, failed: 0, errors: [] });
    };

    const handleClose = () => {
        reset();
        onClose();
    };

    // อ่านไฟล์ CSV
    const handleFile = (file) => {
        const reader = new FileReader();
        reader.onload = (e) => {
            const { headers, rows } = parseCsv(e.target.result);
            if (headers.length === 0) {
                return;
            }
            setCsvHeaders(headers);
            setCsvRows(rows);

            // Auto-map: ถ้า CSV header ตรงกับ dbColumn → map อัตโนมัติ
            const autoMap = {};
            headers.forEach(h => {
                const match = dbColumns.find(
                    dc => dc.value.toLowerCase() === h.toLowerCase() ||
                        dc.label.toLowerCase() === h.toLowerCase()
                );
                if (match) autoMap[h] = match.value;
            });
            setMapping(autoMap);
            setStep(1);
        };
        reader.readAsText(file, 'UTF-8');
        return false; // ไม่ให้ antd upload อัตโนมัติ
    };

    // Import ข้อมูลเข้า Supabase
    const handleImport = async () => {
        setStep(2);
        setImporting(true);

        // สร้าง records จาก mapping
        const records = csvRows.map(row => {
            const record = {};
            Object.entries(mapping).forEach(([csvCol, dbCol]) => {
                if (dbCol && row[csvCol] !== undefined && row[csvCol] !== '') {
                    record[dbCol] = row[csvCol];
                }
            });
            return { data: record, _rowNum: row._rowNum };
        }).filter(r => Object.keys(r.data).length > 0);

        const batchSize = 50;
        let success = 0;
        let failed = 0;
        const errors = [];

        const { supabase } = await import('../../supabaseClient');

        for (let i = 0; i < records.length; i += batchSize) {
            const batch = records.slice(i, i + batchSize);
            const batchData = batch.map(r => r.data);

            try {
                const { error } = await supabase.from(tableName).insert(batchData);
                if (error) {
                    failed += batch.length;
                    errors.push({
                        rows: `${batch[0]._rowNum}-${batch[batch.length - 1]._rowNum}`,
                        message: error.message,
                    });
                } else {
                    success += batch.length;
                }
            } catch (err) {
                failed += batch.length;
                errors.push({
                    rows: `${batch[0]._rowNum}-${batch[batch.length - 1]._rowNum}`,
                    message: err.message,
                });
            }

            setProgress(Math.round(((i + batch.length) / records.length) * 100));
        }

        setResult({ success, failed, errors });
        setImporting(false);
        setStep(3);
    };

    const mappedCount = Object.values(mapping).filter(Boolean).length;
    const previewData = csvRows.slice(0, 5);

    // Preview table แสดงข้อมูล CSV ที่ map แล้ว
    const previewColumns = csvHeaders.map(h => ({
        title: (
            <div className="csv-col-header">
                <div className="csv-col-original">{h}</div>
                <Select
                    size="small"
                    placeholder="เลือก field..."
                    value={mapping[h] || undefined}
                    onChange={(val) => setMapping(prev => ({ ...prev, [h]: val }))}
                    options={[
                        { label: '— ข้าม —', value: '' },
                        ...dbColumns,
                    ]}
                    style={{ width: '100%', marginTop: 4 }}
                    allowClear
                />
            </div>
        ),
        dataIndex: h,
        key: h,
        width: 160,
        ellipsis: true,
    }));

    return (
        <Modal
            title="📥 นำเข้าข้อมูลจาก CSV"
            open={open}
            onCancel={handleClose}
            width={820}
            className="crud-modal csv-import-modal"
            footer={null}
            destroyOnClose
        >
            <Steps
                current={step}
                size="small"
                className="csv-steps"
                items={[
                    { title: 'เลือกไฟล์' },
                    { title: 'ตรวจสอบ' },
                    { title: 'นำเข้า' },
                    { title: 'ผลลัพธ์' },
                ]}
            />

            <div className="csv-step-content">
                {/* Step 0: Upload */}
                {step === 0 && (
                    <div className="csv-upload-zone">
                        <Dragger
                            accept=".csv,.txt"
                            showUploadList={false}
                            beforeUpload={handleFile}
                            multiple={false}
                        >
                            <div className="csv-upload-inner">
                                <CloudUploadOutlined className="csv-upload-icon" />
                                <p className="csv-upload-text">ลากไฟล์ CSV มาวางที่นี่</p>
                                <p className="csv-upload-hint">หรือกดเพื่อเลือกไฟล์ · รองรับ .csv, .txt (UTF-8)</p>
                            </div>
                        </Dragger>
                        <div className="csv-tips">
                            <Alert
                                type="info"
                                showIcon
                                message="คำแนะนำ"
                                description={
                                    <ul style={{ margin: 0, paddingLeft: 16 }}>
                                        <li>ไฟล์ CSV ต้องมีแถวหัวข้อ (header) เป็นแถวแรก</li>
                                        <li>รองรับตัวคั่นทั้งเครื่องหมายจุลภาค (,) และ semicolon (;)</li>
                                        <li>ถ้าคอลัมน์ CSV ชื่อตรงกับชื่อ field ในระบบ จะ map ให้อัตโนมัติ</li>
                                    </ul>
                                }
                            />
                        </div>
                    </div>
                )}

                {/* Step 1: Preview + Column Mapping */}
                {step === 1 && (
                    <div className="csv-preview">
                        <div className="csv-preview-info">
                            <Space>
                                <Tag color="blue"><FileTextOutlined /> {csvRows.length} แถว</Tag>
                                <Tag color="green">{csvHeaders.length} คอลัมน์</Tag>
                                <Tag color={mappedCount > 0 ? 'green' : 'red'}>
                                    map แล้ว {mappedCount}/{csvHeaders.length}
                                </Tag>
                            </Space>
                        </div>
                        <div className="csv-mapping-hint">
                            เลือก field ที่ต้องการ map ในแต่ละคอลัมน์ (คอลัมน์ที่ไม่ได้ map จะถูกข้าม)
                        </div>
                        <Table
                            dataSource={previewData}
                            columns={previewColumns}
                            rowKey="_rowNum"
                            pagination={false}
                            scroll={{ x: 'max-content' }}
                            size="small"
                            className="csv-preview-table"
                        />
                        {csvRows.length > 5 && (
                            <div className="csv-preview-more">
                                ... แสดง 5 จาก {csvRows.length} แถว
                            </div>
                        )}
                        <div className="csv-preview-actions">
                            <Button onClick={() => { reset(); }}>
                                เลือกไฟล์ใหม่
                            </Button>
                            <Button
                                type="primary"
                                icon={<ArrowRightOutlined />}
                                onClick={handleImport}
                                disabled={mappedCount === 0}
                                className="add-btn"
                            >
                                นำเข้า {csvRows.length} แถว
                            </Button>
                        </div>
                    </div>
                )}

                {/* Step 2: Importing */}
                {step === 2 && (
                    <div className="csv-importing">
                        <div className="csv-importing-icon">📤</div>
                        <h3>กำลังนำเข้าข้อมูล...</h3>
                        <Progress
                            percent={progress}
                            status="active"
                            strokeColor={{ '0%': '#1a7f37', '100%': '#2da44e' }}
                            style={{ maxWidth: 400, margin: '16px auto' }}
                        />
                        <p className="csv-importing-hint">กรุณาอย่าปิดหน้าต่างนี้</p>
                    </div>
                )}

                {/* Step 3: Results */}
                {step === 3 && (
                    <div className="csv-result">
                        <div className="csv-result-icon">
                            {result.failed === 0 ? '🎉' : '⚠️'}
                        </div>
                        <h3>นำเข้าเสร็จสิ้น</h3>

                        <div className="csv-result-stats">
                            <div className="csv-result-stat success">
                                <CheckCircleOutlined />
                                <span>{result.success} สำเร็จ</span>
                            </div>
                            {result.failed > 0 && (
                                <div className="csv-result-stat failed">
                                    <WarningOutlined />
                                    <span>{result.failed} ล้มเหลว</span>
                                </div>
                            )}
                        </div>

                        {result.errors.length > 0 && (
                            <div className="csv-result-errors">
                                <Alert
                                    type="error"
                                    showIcon
                                    message="รายละเอียดข้อผิดพลาด"
                                    description={
                                        <ul style={{ margin: 0, paddingLeft: 16, maxHeight: 150, overflow: 'auto' }}>
                                            {result.errors.map((err, i) => (
                                                <li key={i}>แถว {err.rows}: {err.message}</li>
                                            ))}
                                        </ul>
                                    }
                                />
                            </div>
                        )}

                        <div className="csv-result-actions">
                            <Button onClick={handleClose}>ปิด</Button>
                            <Button
                                type="primary"
                                className="add-btn"
                                onClick={() => {
                                    if (onSuccess) onSuccess();
                                    handleClose();
                                }}
                            >
                                เสร็จสิ้น
                            </Button>
                        </div>
                    </div>
                )}
            </div>
        </Modal>
    );
}

