    'กลุ่มส่งเสริมและพัฒนาเกษตรกร': 'development',
    'กลุ่มอารักขาพืช': 'protection',
};

// เมนูทั้งหมด (พร้อม group key)
const allMenuItems = [
    {
        key: '/dashboard',
        icon: <DashboardOutlined />,
        label: 'แดชบอร์ดรวม',
    },
    {
        key: 'admin',
        group: 'admin',
        icon: <TeamOutlined />,
        label: 'ฝ่ายบริหารทั่วไป',
        children: [
            { key: '/dashboard/admin/overview', icon: <PieChartOutlined />, label: 'Dashboard กลุ่ม' },
            { key: '/dashboard/admin/personnel', icon: <TeamOutlined />, label: 'ข้อมูลบุคลากร' },
            { key: '/dashboard/admin/assets', icon: <CarOutlined />, label: 'พัสดุ/ครุภัณฑ์' },
            { key: '/dashboard/admin/budgets', icon: <DollarOutlined />, label: 'งบประมาณ' },
        ],
    },
    {
        key: 'strategy',
        group: 'strategy',
        icon: <AimOutlined />,
        label: 'ยุทธศาสตร์ฯ',
        children: [
            { key: '/dashboard/strategy/overview', icon: <PieChartOutlined />, label: 'Dashboard กลุ่ม' },
            { key: '/dashboard/strategy/farmer-registry', icon: <FileTextOutlined />, label: 'ทะเบียนเกษตรกร' },
            { key: '/dashboard/strategy/gis', icon: <GlobalOutlined />, label: 'พิกัด GIS' },
            { key: '/dashboard/strategy/disasters', icon: <ThunderboltOutlined />, label: 'ภัยพิบัติ' },
            { key: '/dashboard/strategy/kpi', icon: <AimOutlined />, label: 'แผน/KPI' },
        ],
    },
    {
        key: 'production',
        group: 'production',
        icon: <BankOutlined />,
        label: 'ส่งเสริมการผลิต',
        children: [
            { key: '/dashboard/production/overview', icon: <PieChartOutlined />, label: 'Dashboard กลุ่ม' },
            { key: '/dashboard/production/large-plots', icon: <BankOutlined />, label: 'แปลงใหญ่' },
            { key: '/dashboard/production/learning-centers', icon: <BankOutlined />, label: 'ศพก.' },
            { key: '/dashboard/production/certifications', icon: <SafetyCertificateOutlined />, label: 'มาตรฐาน GAP' },
            { key: '/dashboard/production/crop-production', icon: <BarChartOutlined />, label: 'ผลผลิตพืช' },
        ],
    },
    {
        key: 'development',
        group: 'development',
        icon: <ShopOutlined />,
        label: 'ส่งเสริมเกษตรกร',
        children: [
            { key: '/dashboard/development/overview', icon: <PieChartOutlined />, label: 'Dashboard กลุ่ม' },
            { key: '/dashboard/development/community-enterprises', icon: <ShopOutlined />, label: 'วิสาหกิจชุมชน' },
            { key: '/dashboard/development/smart-farmers', icon: <UserSwitchOutlined />, label: 'เกษตรกรรุ่นใหม่' },
            { key: '/dashboard/development/farmer-groups', icon: <UsergroupAddOutlined />, label: 'กลุ่มแม่บ้าน/ยุวฯ' },
            { key: '/dashboard/development/agri-tourism', icon: <EnvironmentOutlined />, label: 'ท่องเที่ยวเกษตร' },
        ],
    },
    {
        key: 'protection',
        group: 'protection',
        icon: <BugOutlined />,
        label: 'อารักขาพืช',
        children: [
            { key: '/dashboard/protection/overview', icon: <PieChartOutlined />, label: 'Dashboard กลุ่ม' },
            { key: '/dashboard/protection/pest-outbreaks', icon: <BugOutlined />, label: 'พื้นที่ระบาด' },
            { key: '/dashboard/protection/pest-centers', icon: <MedicineBoxOutlined />, label: 'ศจช.' },
            { key: '/dashboard/protection/biocontrol', icon: <ExperimentOutlined />, label: 'ชีวภัณฑ์' },
            { key: '/dashboard/protection/fire-hotspots', icon: <FireOutlined />, label: 'จุดเฝ้าระวัง PM2.5' },
        ],
    },
];

// เมนูสำหรับ admin เท่านั้น
const adminOnlyItems = [
    { type: 'divider' },
    {
        key: 'system',
        icon: <SafetyCertificateOutlined />,
        label: 'ระบบ',
        children: [
            { key: '/dashboard/admin/users', icon: <TeamOutlined />, label: 'จัดการสิทธิ์ผู้ใช้' },
            { key: '/dashboard/admin/audit-log', icon: <HistoryOutlined />, label: 'ประวัติการแก้ไข' },
        ],
    },
];

function getFilteredMenuItems(role, department) {
    // Admin เห็นทุกเมนู
    if (role === 'admin') {
        return [...allMenuItems, ...adminOnlyItems];
    }

    // editor/viewer เห็นเฉพาะ Dashboard รวม + กลุ่มงานตัวเอง
    const userGroup = department ? GROUP_KEYS[department] : null;
    const filtered = allMenuItems.filter(item => {
        // Dashboard รวม เห็นเสมอ
        if (item.key === '/dashboard') return true;
        // กลุ่มงานของตัวเอง
        if (item.group && item.group === userGroup) return true;
        // ไม่มีกลุ่มงานก็เห็นทุกกลุ่ม (fallback)
        if (!userGroup && item.group) return true;
        return false;
    });
    return filtered;
}

const bottomMenuItems = [
    { key: 'home', icon: <HomeOutlined />, label: 'กลับหน้าหลัก' },
    { key: 'logout', icon: <LogoutOutlined />, label: 'ออกจากระบบ', danger: true },
];

function SidebarContent({ user, onMenuClick, location, menuItems }) {
    const openKeys = menuItems
        .filter(item => item.children)
        .filter(item => item.children.some(child => location.pathname.startsWith(child.key)))
        .map(item => item.key);

    return (
        <>
            <div className="sidebar-header">
                <div className="sidebar-brand">
                    <span className="brand-icon">🌾</span>
                    <div>
                        <div>สนง.เกษตรจังหวัด</div>
                        <div style={{ fontSize: 12, fontWeight: 400, opacity: 0.6 }}>นครปฐม</div>
                    </div>
                </div>
            </div>

            <Menu
                mode="inline"
                selectedKeys={[location.pathname]}
                defaultOpenKeys={openKeys}
                items={menuItems}
                onClick={onMenuClick}
            />

            <div className="sidebar-bottom-menu">
                <Menu
                    mode="inline"
                    selectable={false}
                    items={bottomMenuItems}
                    onClick={({ key }) => onMenuClick({ key })}
                    style={{ background: 'transparent', border: 'none' }}
                />
            </div>
        </>
    );
}

export default function Sidebar({ user, mobileOpen, onMobileClose }) {
    const navigate = useNavigate();
    const location = useLocation();
    const { role, department } = useAuth();
    const [collapsed, setCollapsed] = useState(false);

    const menuItems = getFilteredMenuItems(role, department);

    const handleMenuClick = async ({ key }) => {
        if (key === 'logout') {
            await supabase.auth.signOut();
            navigate('/');
        } else if (key === 'home') {
            navigate('/');
        } else {
            navigate(key);
        }
        if (onMobileClose) onMobileClose();
    };

    return (
        <>
            {/* Desktop Sidebar */}
            <Sider
                className="sidebar sidebar-desktop"
                width={260}
                collapsible
                collapsed={collapsed}
                onCollapse={setCollapsed}
                breakpoint="lg"
                trigger={null}
            >
                {collapsed ? (
                    <div className="sidebar-header">
                        <div style={{ textAlign: 'center', fontSize: 28 }}>🌾</div>
                    </div>
                ) : null}
                {!collapsed && (
                    <SidebarContent
                        user={user}
                        onMenuClick={handleMenuClick}
                        location={location}
                        menuItems={menuItems}
                    />
                )}
                {collapsed && (
                    <>
                        <Menu
                            mode="inline"
                            selectedKeys={[location.pathname]}
                            items={menuItems}
                            onClick={handleMenuClick}
                        />
                    </>
                )}
            </Sider>

            {/* Mobile Drawer */}
            <Drawer
                placement="left"
                open={mobileOpen}
                onClose={onMobileClose}
                width={280}
                className="mobile-sidebar-drawer"
                styles={{ body: { padding: 0, background: '#0d1117' } }}
            >
                <SidebarContent
                    user={user}
                    onMenuClick={handleMenuClick}
                    location={location}
                    menuItems={menuItems}
                />
            </Drawer>
        </>
    );
}

import { Skeleton } from 'antd';

export default function PageSkeleton() {
    return (
        <div className="page-skeleton">
            {/* Stat Cards Skeleton */}
            <div className="skeleton-stat-row">
                {[1, 2, 3, 4].map(i => (
                    <div key={i} className="skeleton-stat-card">
                        <div className="skeleton-stat-icon">
                            <Skeleton.Avatar active size={40} shape="square" />
                        </div>
                        <Skeleton active paragraph={{ rows: 1, width: '60%' }} title={{ width: '40%' }} />
                    </div>
                ))}
            </div>

            {/* Table Skeleton */}
            <div className="skeleton-table-card">
                <div className="skeleton-table-header">
                    <Skeleton.Input active size="large" style={{ width: 200 }} />
                    <div className="skeleton-table-actions">
                        <Skeleton.Input active size="default" style={{ width: 120 }} />
                        <Skeleton.Button active size="default" />
                    </div>
                </div>
                <div className="skeleton-table-body">
                    {[1, 2, 3, 4, 5].map(i => (
                        <div key={i} className="skeleton-table-row">
                            <Skeleton active paragraph={false} title={{ width: `${60 + Math.random() * 30}%` }} />
                        </div>
                    ))}
                </div>
            </div>
        </div>
    );
}

import { createContext, useContext, useEffect, useState } from 'react';
import { supabase } from '../supabaseClient';

const AuthContext = createContext(null);

// กลุ่มงาน → group key mapping
const DEPARTMENT_GROUP_MAP = {
    'ฝ่ายบริหารทั่วไป': 'admin',
    'กลุ่มยุทธศาสตร์และสารสนเทศ': 'strategy',
    'กลุ่มส่งเสริมและพัฒนาการผลิต': 'production',
    'กลุ่มส่งเสริมและพัฒนาเกษตรกร': 'development',
    'กลุ่มอารักขาพืช': 'protection',
};

// group key → tables ที่อยู่ในกลุ่ม
const GROUP_TABLES = {
    admin: ['personnel', 'assets', 'budgets'],
    strategy: ['farmer_registry', 'gis_areas', 'disasters', 'kpi_plans'],
    production: ['large_plots', 'learning_centers', 'certifications', 'crop_production'],
    development: ['community_enterprises', 'smart_farmers', 'farmer_groups', 'agri_tourism'],
    protection: ['pest_outbreaks', 'pest_centers', 'biocontrol_stock', 'fire_hotspots'],
};

export function AuthProvider({ children }) {
    const [user, setUser] = useState(null);
    const [profile, setProfile] = useState(null);
    const [loading, setLoading] = useState(true);

    // ดึง profile จากตาราง profiles
    const fetchProfile = async (userId) => {
        try {
            const { data, error } = await supabase
                .from('profiles')
                .select('*')
                .eq('id', userId)
                .single();
            if (error) throw error;
            setProfile(data);
        } catch (err) {
            console.error('Error fetching profile:', err);
            // ถ้ายังไม่มี profile ให้ set default
            setProfile({ role: 'viewer', department: null });
        }
    };

    useEffect(() => {
        supabase.auth.getSession().then(({ data: { session } }) => {
            const u = session?.user ?? null;
            setUser(u);
            if (u) {
                fetchProfile(u.id);
            }
            setLoading(false);
        });

        const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
            const u = session?.user ?? null;
            setUser(u);
            if (u) {
                fetchProfile(u.id);
            } else {
                setProfile(null);
            }
        });

        return () => subscription.unsubscribe();
    }, []);

    // Helper functions
    const role = profile?.role || 'viewer';
    const department = profile?.department || null;
    const groupKey = department ? DEPARTMENT_GROUP_MAP[department] : null;

    const isAdmin = () => role === 'admin';
    const canEdit = () => role === 'admin' || role === 'editor';
    const canDelete = () => role === 'admin';

    // ตรวจสอบว่าผู้ใช้สามารถเข้าถึงกลุ่มงานนี้ได้หรือไม่
    const canAccessGroup = (targetGroup) => {
        if (role === 'admin') return true;
        return groupKey === targetGroup;
    };

    // ตรวจสอบว่าผู้ใช้สามารถเข้าถึงตารางนี้ได้หรือไม่
    const canAccessTable = (tableName) => {
        if (role === 'admin') return true;
        if (!groupKey) return false;
        return GROUP_TABLES[groupKey]?.includes(tableName) || false;
    };

    const value = {
        user,
        profile,
        loading,
        role,
        department,
        groupKey,
        isAdmin,
        canEdit,
        canDelete,
        canAccessGroup,
        canAccessTable,
        refreshProfile: () => user && fetchProfile(user.id),
    };

    return (
        <AuthContext.Provider value={value}>
            {children}
        </AuthContext.Provider>
    );
}

export function useAuth() {
    const context = useContext(AuthContext);
    if (!context) {
        throw new Error('useAuth must be used within AuthProvider');
    }
    return context;
}

export { DEPARTMENT_GROUP_MAP, GROUP_TABLES };

import { useEffect, useRef, useState } from 'react';
import { Modal } from 'antd';
import { LogoutOutlined, ReloadOutlined } from '@ant-design/icons';
import { supabase } from '../supabaseClient';

/**
 * Hook ที่ตรวจสอบ session expiry ของ Supabase
 * แสดง Modal เตือน 5 นาทีก่อน session หมดอายุ
 */
export function useSessionTimeout() {
    const [showWarning, setShowWarning] = useState(false);
    const [countdown, setCountdown] = useState(300); // 5 นาที
    const timerRef = useRef(null);
    const countdownRef = useRef(null);

    const clearTimers = () => {
        if (timerRef.current) clearTimeout(timerRef.current);
        if (countdownRef.current) clearInterval(countdownRef.current);
    };

    const scheduleWarning = (session) => {
        clearTimers();
        if (!session) return;

        const expiresAt = session.expires_at; // Unix timestamp in seconds
        if (!expiresAt) return;

        const now = Math.floor(Date.now() / 1000);
        const timeUntilExpiry = expiresAt - now;
        const warningTime = timeUntilExpiry - 300; // 5 นาทีก่อนหมดอายุ

        if (warningTime <= 0) {
            // น้อยกว่า 5 นาที → แสดงเตือนทันที
            setShowWarning(true);
            setCountdown(Math.max(0, timeUntilExpiry));
            startCountdown(Math.max(0, timeUntilExpiry));
        } else {
            timerRef.current = setTimeout(() => {
                setShowWarning(true);
                setCountdown(300);
                startCountdown(300);
            }, warningTime * 1000);
        }
    };

    const startCountdown = (seconds) => {
        let remaining = seconds;
        countdownRef.current = setInterval(() => {
            remaining -= 1;
            setCountdown(remaining);
            if (remaining <= 0) {
                clearInterval(countdownRef.current);
                handleLogout();
            }
        }, 1000);
    };

    const handleRefresh = async () => {
        try {
            const { data, error } = await supabase.auth.refreshSession();
            if (error) throw error;
            setShowWarning(false);
            clearTimers();
            if (data.session) {
                scheduleWarning(data.session);
            }
        } catch {
            handleLogout();
        }
    };

    const handleLogout = async () => {
        clearTimers();
        setShowWarning(false);
        await supabase.auth.signOut();
        window.location.href = '/login';
    };

    useEffect(() => {
        supabase.auth.getSession().then(({ data: { session } }) => {
            if (session) scheduleWarning(session);
        });

        const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
            if (session) {
                scheduleWarning(session);
            } else {
                clearTimers();
            }
        });

        return () => {
            clearTimers();
            subscription.unsubscribe();
        };
    }, []);

    const formatTime = (seconds) => {
        const m = Math.floor(seconds / 60);
        const s = seconds % 60;
        return `${m}:${s.toString().padStart(2, '0')}`;
    };

    const WarningModal = () => (
        <Modal
            title="⏰ Session กำลังจะหมดอายุ"
            open={showWarning}
            closable={false}
            maskClosable={false}
            okText="ต่ออายุ Session"
            cancelText="ออกจากระบบ"
            onOk={handleRefresh}
            onCancel={handleLogout}
            okButtonProps={{ icon: <ReloadOutlined />, className: 'add-btn' }}
            cancelButtonProps={{ icon: <LogoutOutlined />, danger: true }}
            className="crud-modal"
        >
            <div style={{ textAlign: 'center', padding: '16px 0' }}>
                <div style={{ fontSize: 48, marginBottom: 12 }}>⏳</div>
                <p style={{ fontSize: 16, marginBottom: 8, color: '#1f2328' }}>
                    Session ของคุณจะหมดอายุใน
                </p>
                <div style={{
                    fontSize: 36,
                    fontWeight: 700,
                    color: countdown <= 60 ? '#cf222e' : '#bf8700',
                    fontFamily: 'monospace',
                    marginBottom: 12,
                }}>
                    {formatTime(countdown)}
                </div>
                <p style={{ fontSize: 14, color: '#656d76' }}>
                    กด "ต่ออายุ" เพื่อใช้งานต่อ หรือข้อมูลที่กำลังกรอกอาจหายไป
                </p>
            </div>
        </Modal>
    );

    return { WarningModal };
}

